function addMinsToTimeStr(timeStr: string, mins: number): string {
  const [h, m] = timeStr.split(':').map(Number);
  let total = h * 60 + m + mins;
  if (total < 0) total += 24 * 60;
  const nh = Math.floor(total / 60) % 24;
  const nm = total % 60;
  return `${String(nh).padStart(2, '0')}:${String(nm).padStart(2, '0')}`;
}

// Build lookup map — ishraq is pre-computed from sunrise and stored explicitly.
// This local timetable is the FALLBACK only; the app fetches live values from
// the database (which also stores ishraq) and only uses this if the DB is
// unavailable. Any portal edits to prayer times are picked up from the DB.
const TIMETABLE: Record<string, DayTimetable> = {};
for (const row of RAW) {
  const [date, fajr, sunrise, dhuhr, asr, maghrib, isha, jumuah, hijri, iqFajr, iqDhuhr, iqAsr, iqMaghrib, iqIsha] = row;
  // Ishraq hardcoded as sunrise + 20 min; Zawaal as dhuhr - 30 min
  // (fallback values — DB values take precedence in the app)
  const ishraq = addMinsToTimeStr(sunrise, 20);
  const zawaal = addMinsToTimeStr(dhuhr, -30);
  TIMETABLE[date] = {
    fajr,
    sunrise,
    ishraq,           // explicit pre-computed fallback stored in the map
    zawaal,           // dhuhr - 29 min fallback
    dhuhr,
    asr,
    maghrib,
    isha,
    jumuah: jumuah || null,
    hijri,
    iqFajr, iqDhuhr, iqAsr, iqMaghrib, iqIsha,
  };
}

export function getTodayKey(): string {
  const now = new Date();
  const dd = String(now.getDate()).padStart(2, '0');
  const mm = String(now.getMonth() + 1).padStart(2, '0');
  const yyyy = now.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

export function getDateKey(date: Date): string {
  const dd = String(date.getDate()).padStart(2, '0');
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  const yyyy = date.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

export function lookupTimetable(date?: Date): DayTimetable | null {
  const key = date ? getDateKey(date) : getTodayKey();
  return TIMETABLE[key] ?? null;
}

export default TIMETABLE;
